import { describe, expect, it, vi } from "vitest";
import { run } from "../../.claude/hooks/pre-read-json-csv-compact.mjs";

const bigJson = (n) =>
	JSON.stringify(
		Array.from({ length: n }, (_, i) => ({
			id: i,
			name: `user_${i}`,
			email: `u${i}@x.com`,
		})),
	);
const bigCsv = (n) =>
	[
		"id,name,email",
		...Array.from({ length: n }, (_, i) => `${i},user_${i},u${i}@x.com`),
	].join("\n");
const bigJsonl = (n) =>
	Array.from({ length: n }, (_, i) =>
		JSON.stringify({ id: i, val: i * 2 }),
	).join("\n");

function makeDeps(content, size = 100_000) {
	return {
		readFile: vi.fn(() => content),
		exists: vi.fn(() => true),
		stat: vi.fn(() => ({ size })),
	};
}

describe("pre-read-json-csv-compact", () => {
	it("laisse passer si tool_name != Read", () => {
		expect(
			run({ tool_name: "Write", tool_input: { file_path: "data.json" } }),
		).toBeNull();
	});

	it("laisse passer si extension non supportée", () => {
		expect(
			run({ tool_name: "Read", tool_input: { file_path: "file.ts" } }),
		).toBeNull();
	});

	it("laisse passer si le fichier n'existe pas", () => {
		const deps = {
			readFile: vi.fn(),
			exists: vi.fn(() => false),
			stat: vi.fn(() => ({ size: 100_000 })),
		};
		expect(
			run({ tool_name: "Read", tool_input: { file_path: "big.json" } }, deps),
		).toBeNull();
	});

	it("laisse passer si fichier petit (< seuil)", () => {
		const content = JSON.stringify([{ id: 1 }]);
